initial_model.plantuml:
@startuml
class Customer {
    - customerId : String
}
class Order {
    - orderId : String
}
class Product {
    - name : String
    - description : String
}
class OrderItem {
    - quantity : Integer
    - agreedPrice : Decimal
}
class Review {
    - dateWritten : Date
    - ratingScore : Integer
}
class Promotion {
    - promotionId : String
}
class ProductPromotion {
    - discountRate : Decimal
    - startDate : Date
    - endDate : Date
}
Customer "1" -- "0..*"  Order : Places
Product "1" -- "0..*"  ProductPromotion : HasPromotion
Promotion "1" -- "0..*"  ProductPromotion : AppliesTo
Order "1" *-- "1..*"  OrderItem : Order_Contains_OrderItem
OrderItem "1" *-- "1"  Product
(Customer, Product) .. Review
(Product, Promotion) .. ProductPromotion
@enduml

